#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int *A = (int*)malloc(N * sizeof(int));
        int *B = (int*)malloc(M * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        for (int i = 0; i < M; ++i) scanf("%d", &B[i]);
        int i = 0, j = 0;
        while (i < N && j < M) {
            if (A[i] <= B[j]) {
                printf("%d ", A[i]);
                ++i;
            } else {
                printf("%d ", B[j]);
                ++j;
            }
        }
        while (i < N) { printf("%d ", A[i]); ++i; }
        while (j < M) { printf("%d ", B[j]); ++j; }
        printf("\n");
        free(A);
        free(B);
    }
    return 0;
}

