import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        B = [int(next(it)) for _ in range(M)]
        i=j=0
        merged=[]
        while i<N and j<M:
            if A[i]<=B[j]:
                merged.append(str(A[i])); i+=1
            else:
                merged.append(str(B[j])); j+=1
        while i<N:
            merged.append(str(A[i])); i+=1
        while j<M:
            merged.append(str(B[j])); j+=1
        out_lines.append(' '.join(merged))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

